function Disable-ADInactiveUsers {
    param(
        [int]$Jours      = 90,
        [string]$Rapport = "C:\Logs\Inactifs_$(Get-Date -f yyyyMMdd).csv",
        [switch]$WhatIf
    )

    $Limite  = (Get-Date).AddDays(-$Jours)
    $Comptes = Get-ADUser -Filter {
        LastLogonDate -lt $Limite -and Enabled -eq $true
    } -Properties LastLogonDate, Department |
    Where-Object { $_.DistinguishedName -notlike "*OU=ServiceAccounts*" }

    $Résultat = foreach ($U in $Comptes) {
        if (-not $WhatIf) { Disable-ADAccount -Identity $U.SamAccountName }
        [PSCustomObject]@{
            SamAccountName    = $U.SamAccountName
            Nom               = $U.Name
            Departement       = $U.Department
            DerniereConnexion = $U.LastLogonDate
            Action            = if ($WhatIf) { "SIMULATION" } else { "DESACTIVE" }
        }
    }

    $Résultat | Export-Csv -Path $Rapport -NoTypeInformation -Encoding UTF8
    Write-Host "$($Résultat.Count) comptes traités — Rapport : $Rapport"
}

function Get-ADGroupMembersReport {
    param(
        [Parameter(Mandatory)][string]$GroupName,
        [string]$Output = "C:\Logs\Groupe_$GroupName.csv"
    )

    function Get-Recursive {
        param([string]$Group, [string]$Parent = "Direct")
        Get-ADGroupMember -Identity $Group | ForEach-Object {
            if ($_.objectClass -eq 'group') {
                Get-Recursive -Group $_.SamAccountName -Parent $Group
            } else {
                $U = Get-ADUser $_.SamAccountName -Properties EmailAddress,Department,Enabled
                [PSCustomObject]@{
                    Login        = $U.SamAccountName
                    Nom          = $U.Name
                    Email        = $U.EmailAddress
                    Departement  = $U.Department
                    Actif        = $U.Enabled
                    GroupeParent = $Parent
                }
            }
        }
    }

    $Membres = Get-Recursive -Group $GroupName
    $Membres | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Host "$($Membres.Count) membres exportés vers $Output"
}

function Reset-ADUserPassword {
    param(
        [Parameter(Mandatory)][string]$SamAccountName,
        [string]$NewPassword = ""
    )

    if (-not $NewPassword) {
        Add-Type -AssemblyName System.Web
        $NewPassword = [System.Web.Security.Membership]::GeneratePassword(14,3)
    }

    $SecurePwd = ConvertTo-SecureString $NewPassword -AsPlainText -Force

    try {
        Unlock-ADAccount      -Identity $SamAccountName
        Set-ADAccountPassword -Identity $SamAccountName -NewPassword $SecurePwd -Reset
        Set-ADUser            -Identity $SamAccountName -ChangePasswordAtLogon $true

        Write-Host "Compte $SamAccountName réinitialisé." -ForegroundColor Green
        Write-Host "Mot de passe : $NewPassword"
        return $NewPassword
    } catch {
        Write-Error "Erreur : $_"
    }
}

# CSV requis : SamAccountName, Title, Department, Manager, PhoneNumber
function Sync-ADUsersFromCSV {
    param(
        [Parameter(Mandatory)][string]$CSVPath,
        [switch]$WhatIf
    )

    $Users   = Import-Csv -Path $CSVPath -Encoding UTF8
    $Results = foreach ($Row in $Users) {
        try {
            $Params = @{
                Identity    = $Row.SamAccountName
                Title       = $Row.Title
                Department  = $Row.Department
                OfficePhone = $Row.PhoneNumber
            }
            if ($Row.Manager) {
                $Params.Manager = (Get-ADUser $Row.Manager).DistinguishedName
            }
            if (-not $WhatIf) { Set-ADUser @Params }
            [PSCustomObject]@{ User=$Row.SamAccountName; Status="OK" }
        } catch {
            [PSCustomObject]@{ User=$Row.SamAccountName; Status="ERREUR"; Detail=$_.Exception.Message }
        }
    }

    $Results | Format-Table -AutoSize
    Write-Host "OK:$(($Results|Where Status -eq OK).Count)  Erreurs:$(($Results|Where Status -eq ERREUR).Count)"
}

function Connect-EXOSafe {
    param(
        [string]$UPN   = "",
        [switch]$Force
    )

    if (-not $Force) {
        try {
            if (Get-ConnectionInformation -ErrorAction Stop) {
                Write-Host "Déjà connecté à Exchange Online." -ForegroundColor Green
                return
            }
        } catch {}
    }

    if (-not (Get-Module -ListAvailable ExchangeOnlineManagement)) {
        Write-Host "Installation du module ExchangeOnlineManagement..."
        Install-Module ExchangeOnlineManagement -Force -Scope CurrentUser
    }

    Import-Module ExchangeOnlineManagement
    $P = @{ ShowBanner = $false }
    if ($UPN) { $P.UserPrincipalName = $UPN }

    try {
        Connect-ExchangeOnline @P
        Write-Host "Connecté à Exchange Online." -ForegroundColor Green
    } catch {
        Write-Error "Connexion impossible : $_"
    }
}

function Get-MailboxSizeReport {
    param(
        [string]$Output = "C:\Logs\MailboxSizes_$(Get-Date -f yyyyMMdd).csv",
        [int]$Top = 0
    )

    $Mailboxes = Get-Mailbox -ResultSize Unlimited -RecipientTypeDetails UserMailbox
    $Report = $Mailboxes | ForEach-Object {
        $Stats  = Get-MailboxStatistics -Identity $_.ExchangeGuid
        $SizeMB = [math]::Round($Stats.TotalItemSize.Value.ToBytes() / 1MB, 2)
        [PSCustomObject]@{
            DisplayName       = $_.DisplayName
            UPN               = $_.UserPrincipalName
            TailleMB          = $SizeMB
            NbItems           = $Stats.ItemCount
            DerniereConnexion = $Stats.LastLogonTime
            Quota             = $_.ProhibitSendReceiveQuota
        }
    } | Sort-Object TailleMB -Descending

    if ($Top -gt 0) { $Report = $Report | Select-Object -First $Top }
    $Report | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Host "$($Report.Count) boîtes exportées vers $Output"
}

function New-SharedMailboxComplete {
    param(
        [Parameter(Mandatory)][string]$DisplayName,
        [Parameter(Mandatory)][string]$Alias,
        [string]$Domain         = "contoso.com",
        [string[]]$FullAccessTo = @(),
        [string[]]$SendAsTo     = @()
    )

    $Email = "$Alias@$Domain"

    try {
        New-Mailbox -Shared -Name $DisplayName -DisplayName $DisplayName `
            -Alias $Alias -PrimarySmtpAddress $Email
        Write-Host "Boîte $Email créée." -ForegroundColor Green
        Start-Sleep -Seconds 5

        foreach ($U in $FullAccessTo) {
            Add-MailboxPermission -Identity $Email -User $U `
                -AccessRights FullAccess -InheritanceType All -AutoMapping $true
            Write-Host "  FullAccess accordé à $U"
        }
        foreach ($U in $SendAsTo) {
            Add-RecipientPermission -Identity $Email -Trustee $U `
                -AccessRights SendAs -Confirm:$false
            Write-Host "  SendAs accordé à $U"
        }
    } catch {
        Write-Error "Erreur : $_"
    }
}

function Get-ExternalForwardAudit {
    param(
        [string]$Output = "C:\Logs\ExternalForwards_$(Get-Date -f yyyyMMdd).csv"
    )

    $Forwards = Get-Mailbox -ResultSize Unlimited |
        Where-Object { $_.ForwardingAddress -or $_.ForwardingSmtpAddress } |
        ForEach-Object {
            [PSCustomObject]@{
                UPN         = $_.UserPrincipalName
                DisplayName = $_.DisplayName
                ForwardVers = $_.ForwardingSmtpAddress ?? $_.ForwardingAddress
                GarderCopie = $_.DeliverToMailboxAndForward
                Détecté     = Get-Date -Format "yyyy-MM-dd HH:mm"
            }
        }

    if ($Forwards.Count -eq 0) {
        Write-Host "Aucun forward externe détecté." -ForegroundColor Green
        return
    }

    $Forwards | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Warning "$($Forwards.Count) forward(s) externe(s) ! Rapport : $Output"
    $Forwards | Format-Table -AutoSize
}

function New-CustomTransportRule {
    param(
        [Parameter(Mandatory)][string]$Nom,
        [string[]]$DomainesBloqués = @(),
        [string[]]$MotsClésSujet   = @(),
        [string]$Action            = "Reject",
        [string]$RedirectVers      = "",
        [string]$MessageRefus      = "Message bloqué par la politique de sécurité."
    )

    $P = @{ Name=$Nom; Priority=0; Enabled=$true }
    if ($DomainesBloqués) { $P.SenderDomainIs       = $DomainesBloqués }
    if ($MotsClésSujet)   { $P.SubjectContainsWords = $MotsClésSujet   }

    switch ($Action) {
        "Reject"    { $P.RejectMessageReasonText = $MessageRefus }
        "Redirect"  { $P.RedirectMessageTo = $RedirectVers }
        "AddHeader" { $P.SetHeaderName="X-Flag"; $P.SetHeaderValue="Suspicious" }
    }

    try {
        New-TransportRule @P
        Write-Host "Règle '$Nom' créée." -ForegroundColor Green
    } catch {
        Write-Error "Erreur : $_"
    }
}

function Connect-MgGraphSafe {
    param(
        [string[]]$Scopes = @("User.Read.All","Group.ReadWrite.All","Directory.Read.All"),
        [string]$TenantId     = "",
        [string]$ClientId     = "",
        [string]$ClientSecret = ""
    )

    if (-not (Get-Module -ListAvailable Microsoft.Graph)) {
        Write-Host "Installation du module Microsoft.Graph..."
        Install-Module Microsoft.Graph -Force -Scope CurrentUser
    }

    if ($ClientId -and $ClientSecret -and $TenantId) {
        $Secure = ConvertTo-SecureString $ClientSecret -AsPlainText -Force
        $Cred   = New-Object System.Management.Automation.PSCredential($ClientId, $Secure)
        Connect-MgGraph -TenantId $TenantId -ClientSecretCredential $Cred
        Write-Host "Connecté via App Registration." -ForegroundColor Green
    } else {
        Connect-MgGraph -Scopes $Scopes -TenantId $TenantId
        Write-Host "Connecté de façon interactive." -ForegroundColor Green
    }
}

function Get-EntraLicenseReport {
    param(
        [string]$Output = "C:\Logs\Licences_$(Get-Date -f yyyyMMdd).csv"
    )

    $SkuMap = @{}
    Get-MgSubscribedSku | ForEach-Object { $SkuMap[$_.SkuId] = $_.SkuPartNumber }

    $Rapport = Get-MgUser -All `
        -Property DisplayName,UserPrincipalName,AssignedLicenses,SignInActivity |
    ForEach-Object {
        $Lics = $_.AssignedLicenses | ForEach-Object { $SkuMap[$_.SkuId] ?? $_.SkuId }
        $Cnx  = $_.SignInActivity?.LastSignInDateTime
        [PSCustomObject]@{
            DisplayName        = $_.DisplayName
            UPN                = $_.UserPrincipalName
            Licences           = ($Lics -join "; ")
            NbLicences         = $Lics.Count
            DerniereConnexion  = $Cnx
            InactifAvecLicence = ($Cnx -lt (Get-Date).AddDays(-90) -and $Lics.Count -gt 0)
        }
    }

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    $N = ($Rapport | Where-Object InactifAvecLicence).Count
    Write-Warning "$N utilisateurs inactifs ont encore des licences."
}

function Revoke-EntraUserSessions {
    param(
        [Parameter(Mandatory)][string[]]$UPNs,
        [switch]$DisableAccount
    )

    foreach ($UPN in $UPNs) {
        try {
            $User = Get-MgUser -UserId $UPN -ErrorAction Stop
            Revoke-MgUserSignInSession -UserId $User.Id
            Write-Host "Sessions révoquées : $UPN" -ForegroundColor Green

            if ($DisableAccount) {
                Update-MgUser -UserId $User.Id -AccountEnabled:$false
                Write-Warning "Compte désactivé : $UPN"
            }
        } catch {
            Write-Error "Erreur pour $UPN : $_"
        }
    }
}

function Get-ConditionalAccessAudit {
    param(
        [string]$Output = "C:\Logs\CA_$(Get-Date -f yyyyMMdd).csv"
    )

    $Rapport = Get-MgIdentityConditionalAccessPolicy | ForEach-Object {
        [PSCustomObject]@{
            Nom         = $_.DisplayName
            Statut      = $_.State
            UsersIncl   = ($_.Conditions.Users.IncludeUsers   -join "; ")
            GroupesIncl = ($_.Conditions.Users.IncludeGroups  -join "; ")
            AppsIncl    = ($_.Conditions.Applications.IncludeApplications -join "; ")
            Controles   = ($_.GrantControls?.BuiltInControls  -join "; ")
            MFA         = ($_.GrantControls?.BuiltInControls -contains "mfa")
            Créé        = $_.CreatedDateTime
        }
    }

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Host "$($Rapport.Count) politiques CA exportées."
    $Rapport | Format-Table Nom, Statut, MFA -AutoSize
}

function Invoke-GraphAPI {
    param(
        [Parameter(Mandatory)][string]$Endpoint,
        [string]$Method = "GET",
        [object]$Body   = $null,
        [switch]$GetAll
    )

    $Token   = (Get-MgContext).AccessToken
    $Headers = @{
        Authorization  = "Bearer $Token"
        "Content-Type" = "application/json"
    }
    $URL   = "https://graph.microsoft.com/v1.0/$($Endpoint.TrimStart('/'))"
    $Items = [System.Collections.Generic.List[object]]::new()

    do {
        $P = @{ Uri=$URL; Method=$Method; Headers=$Headers }
        if ($Body -and $Method -ne "GET") {
            $P.Body = ($Body | ConvertTo-Json -Depth 10)
        }
        $R = Invoke-RestMethod @P

        if ($R.value) { $Items.AddRange($R.value) }
        else          { return $R }

        $URL = $R."@odata.nextLink"
    } while ($GetAll -and $URL)

    return $Items
}

function Send-GraphMail {
    param(
        [Parameter(Mandatory)][string]$From,
        [Parameter(Mandatory)][string[]]$To,
        [Parameter(Mandatory)][string]$Subject,
        [Parameter(Mandatory)][string]$Body,
        [string]$BodyType  = "HTML",
        [string[]]$CC      = @(),
        [string[]]$Pieces  = @()
    )

    $ToList = $To | ForEach-Object { @{ emailAddress=@{ address=$_ } } }
    $CCList = $CC | ForEach-Object { @{ emailAddress=@{ address=$_ } } }
    $Attach = $Pieces | ForEach-Object {
        @{
            "@odata.type" = "#microsoft.graph.fileAttachment"
            name          = [IO.Path]::GetFileName($_)
            contentBytes  = [Convert]::ToBase64String([IO.File]::ReadAllBytes($_))
        }
    }

    $Payload = @{
        message = @{
            subject      = $Subject
            body         = @{ contentType=$BodyType; content=$Body }
            toRecipients = $ToList
            ccRecipients = $CCList
            attachments  = $Attach
        }
        saveToSentItems = $true
    }

    $UserId = (Get-MgUser -UserId $From).Id
    Invoke-MgGraphRequest -Method POST `
        -Uri "users/$UserId/sendMail" `
        -Body ($Payload | ConvertTo-Json -Depth 10)

    Write-Host "Email envoyé depuis $From." -ForegroundColor Green
}

function Get-RiskyUsersReport {
    param(
        [string]$RiskLevel = "high",
        [string]$Output    = "C:\Logs\RiskyUsers_$(Get-Date -f yyyyMMdd).csv"
    )

    $URI    = "identityProtection/riskyUsers?`$filter=riskLevel eq '$RiskLevel'"
    $Result = Invoke-MgGraphRequest -Method GET -Uri $URI

    $Rapport = $Result.value | ForEach-Object {
        [PSCustomObject]@{
            UPN         = $_.userPrincipalName
            Nom         = $_.userDisplayName
            RiskLevel   = $_.riskLevel
            RiskState   = $_.riskState
            RiskDetail  = $_.riskDetail
            DerniereMAJ = $_.riskLastUpdatedDateTime
        }
    }

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Warning "$($Rapport.Count) utilisateur(s) à risque '$RiskLevel' détecté(s)."
    return $Rapport
}

function New-TeamsChannel {
    param(
        [Parameter(Mandatory)][string]$TeamId,
        [Parameter(Mandatory)][string]$Nom,
        [string]$Description = "",
        [string]$Type        = "standard"
    )

    $Body = @{
        displayName    = $Nom
        description    = $Description
        membershipType = $Type
    } | ConvertTo-Json

    try {
        $R = Invoke-MgGraphRequest `
            -Method POST `
            -Uri "teams/$TeamId/channels" `
            -Body $Body `
            -ContentType "application/json"

        Write-Host "Channel '$Nom' créé." -ForegroundColor Green
        Write-Host "URL : $($R.webUrl)"
        return $R
    } catch {
        Write-Error "Erreur : $_"
    }
}
